// after
function calculateNewBalance(user, fee){
  const total=user.balance-fee;
  if(total<0)throw new Error('insufficient');
  return total;
}

async function chargeUser(id){
  const user=await db.users.get(id);
  const fee=user.tier==='pro'?100:200;
  const newBalance=calculateNewBalance(user,fee);
  await db.users.update(id,{balance:newBalance});
}

