import {Pool} from 'pg';
const pool=new Pool({...});
async function backfill(){
  while(true){
    const lag=await getReplicaLag();
    if(lag>5)await wait(5000);
    const r=await pool.query('UPDATE table SET derived=compute(other) WHERE id IN (SELECT id FROM table WHERE derived IS NULL LIMIT 1000) RETURNING 1');
    if(!r.rowCount)break;
    await wait(200);
  }
}
